+    ctrl.heal(a, b);
+
+    let entries = collector.entries();
+
+    // Should have: partition_create, message_dropped, partition_heal.
+    let create = entries
+        .iter()
+        .filter(|e| e.action.contains("partition_create"))
+        .count();
+    let drop = entries
+        .iter()
+        .filter(|e| e.action.contains("message_dropped"))
